\section{Worked Examples}\label{sec:examples}
\nopagebreak[4]

\begin{samepage}
\needspace{14\baselineskip}
\begin{examplebox}{Example 1: Finding the Hypotenuse Using Pythagoras' Theorem}
What is the length of the hypotenuse of a right triangle with legs of length 3 cm and 4 cm?

\textbf{Given:}
\begin{itemize}[nosep]
\item Leg 1 = 3 cm
\item Leg 2 = 4 cm
\end{itemize}

\textbf{Required:} Hypotenuse length

\begin{figure}[H]
\centering
\begin{tikzpicture}[scale=1.0]
\coordinate (A) at (0,0);
\coordinate (B) at (3,0);
\coordinate (C) at (0,4);
\draw[blue, very thick] (A) -- (B) node[midway, below] {3 cm};
\draw[blue, very thick] (A) -- (C) node[midway, left] {4 cm};
\draw[red, very thick, dashed] (B) -- (C) node[midway, above right] {$c$};
\draw[thick] (0,0.4) -- (0.4,0.4) -- (0.4,0);
\fill (A) circle (2pt);
\fill (B) circle (2pt);
\fill (C) circle (2pt);
\end{tikzpicture}
\caption{Right triangle with legs labeled 3 cm (horizontal) and 4 cm (vertical), and hypotenuse labeled $c$.}
\end{figure}

\begin{table}[H]
\centering
\begin{tabular}{@{}lll@{}}
\toprule
\textbf{Side} & \textbf{Length} & \textbf{Calculation} \\
\midrule
Leg 1 ($a$) & 3 cm & $a^2 = 9$ \\
Leg 2 ($b$) & 4 cm & $b^2 = 16$ \\
Hypotenuse ($c$) & ? & $c^2 = a^2 + b^2 = 25$ \\
\bottomrule
\end{tabular}
\caption{Summary of triangle sides and calculations.}
\end{table}
\end{examplebox}

\begin{solutionbox}
\textbf{Step 1: Identify the sides of the triangle}\\
Recognize the two given sides as legs of the right triangle. Label the hypotenuse as $c$. Use Pythagoras' theorem to find $c$. Identifying the sides is crucial to applying Pythagoras' theorem correctly.
\begin{align*}
\text{Formula: } a^2 + b^2 &= c^2
\end{align*}

\textbf{Step 2: Apply Pythagoras' theorem}\\
Substitute the values for the legs into the theorem. Calculate the sum of the squares of the legs. Solve for the hypotenuse.
\begin{align*}
\text{Substitution: } 3^2 + 4^2 &= c^2 \\
\text{Calculation: } 9 + 16 &= c^2 \\
\text{Result: } 25 &= c^2
\end{align*}

\textbf{Step 3: Calculate the hypotenuse}\\
Take the square root of both sides to find the hypotenuse. Ensure the result is positive since length cannot be negative.
\begin{align*}
\text{Square root: } c &= \sqrt{25} \\
\text{Result: } c &= 5 \text{ cm}
\end{align*}

\[\boxed{c = 5 \text{ cm}}\]

\textit{Verification:} The calculation is verified by rechecking each step: $3^2 = 9$, $4^2 = 16$, $9 + 16 = 25$, and $\sqrt{25} = 5$.
\end{solutionbox}

\begin{notebox}
\begin{itemize}[nosep]
\item Pythagoras' theorem relates the sides of a right triangle through the equation $a^2 + b^2 = c^2$.
\item The hypotenuse is always the longest side of a right triangle.
\item The $(3, 4, 5)$ triangle is a fundamental Pythagorean triple used extensively in construction and education.
\item This theorem is widely used in construction to ensure structures are built with right angles and in navigation systems to calculate shortest paths.
\end{itemize}
\end{notebox}
\end{samepage}

\begin{samepage}
\needspace{14\baselineskip}
\begin{examplebox}{Example 2: Pythagoras in Real-world Scenarios}
A construction worker needs to find the length of a ladder that will reach from the ground to the top of a 15-foot wall. The base of the ladder is placed 9 feet away from the wall. Using Pythagoras' theorem, what is the length of the ladder?

\textbf{Given:}
\begin{itemize}[nosep]
\item Height of wall: 15 feet
\item Distance from wall: 9 feet
\end{itemize}

\textbf{Required:} Length of the ladder

\begin{figure}[H]
\centering
\begin{tikzpicture}[scale=0.25]
\draw[thick, fill=gray!30] (-1,0) rectangle (0,15);
\node at (-0.5,7.5) [rotate=90] {Wall};
\draw[thick] (0,0) -- (12,0);
\draw[blue, very thick] (0,0) -- (0,15) node[midway, left=3pt] {15 ft};
\draw[blue, very thick] (0,0) -- (9,0) node[midway, below] {9 ft};
\draw[red, very thick] (9,0) -- (0,15) node[midway, above right] {Ladder = ?};
\draw[thick] (0,1) -- (1,1) -- (1,0);
\fill (0,0) circle (8pt);
\fill (9,0) circle (8pt);
\fill (0,15) circle (8pt);
\end{tikzpicture}
\caption{Diagram showing a ladder leaning against a wall, forming a right triangle with the wall (15 ft) and ground distance (9 ft).}
\end{figure}

\begin{table}[H]
\centering
\begin{tabular}{@{}lll@{}}
\toprule
\textbf{Component} & \textbf{Symbol} & \textbf{Value} \\
\midrule
Leg $a$ (wall height) & $a$ & 15 ft \\
Leg $b$ (ground distance) & $b$ & 9 ft \\
Hypotenuse (ladder) & $c$ & ? \\
\midrule
\multicolumn{3}{l}{\textbf{Formula:} $a^2 + b^2 = c^2$} \\
\bottomrule
\end{tabular}
\caption{Pythagorean Theorem reference for the ladder problem.}
\end{table}
\end{examplebox}

\begin{solutionbox}
\textbf{Step 1: Identify the Right Triangle}\\
Recognize that the wall, ground, and ladder form a right triangle. The wall is one leg, the ground distance is the other leg, and the ladder acts as the hypotenuse.
\begin{align*}
\text{Wall (vertical leg): } a &= 15 \text{ ft} \\
\text{Ground (horizontal leg): } b &= 9 \text{ ft} \\
\text{Ladder (hypotenuse): } c &= \text{unknown}
\end{align*}

\textbf{Step 2: Apply Pythagorean Theorem}\\
Use Pythagorean theorem: $a^2 + b^2 = c^2$. Substitute $a = 15$ ft and $b = 9$ ft, then solve for $c$.
\begin{align*}
15^2 + 9^2 &= c^2 \\
225 + 81 &= c^2 \\
306 &= c^2 \\
c &= \sqrt{306} \\
c &\approx 17.49 \text{ ft}
\end{align*}

\[\boxed{c \approx 17.49 \text{ feet}}\]

\textit{Verification:} Verify by recalculating: $15^2 = 225$, $9^2 = 81$, $225 + 81 = 306$, and $\sqrt{306} \approx 17.493$.
\end{solutionbox}

\begin{notebox}
\begin{itemize}[nosep]
\item Understanding the relationship between triangle sides is fundamental to solving distance problems.
\item The Pythagorean theorem is a powerful tool for calculating distances in real-world scenarios.
\item Real-world applications often involve solving for unknown lengths where direct measurement is impractical.
\item This theorem is essential in construction and architecture for ensuring correct measurements and angles.
\end{itemize}
\end{notebox}
\end{samepage}

