\begin{figure}[H]
\centering
\begin{tikzpicture}[scale=0.8]
\node[draw, rectangle, fill=blue!20, minimum width=4cm, minimum height=0.8cm] (start) at (0,0) {Start: Given sides $a$, $b$, $c$};
