\section*{Exercises}
\nopagebreak[4]

\begin{samepage}
\textbf{1.} A right triangle has legs measuring 6 cm and 8 cm. Calculate the length of the hypotenuse.
\end{samepage}

\begin{samepage}
\textbf{2.} Find the length of the missing leg of a right triangle if the hypotenuse is 13 m and one leg is 5 m.
\end{samepage}

\begin{samepage}
\textbf{3.} A rectangular garden measures 12 feet by 16 feet. What is the length of the diagonal path across the garden?
\end{samepage}

\begin{samepage}
\textbf{4.} Determine whether a triangle with sides 7 cm, 24 cm, and 25 cm is a right triangle. Justify your answer.
\end{samepage}

\begin{samepage}
\textbf{5.} A television screen has a diagonal measurement of 55 inches and a width of 48 inches. Calculate the height of the screen.
\end{samepage}

\begin{samepage}
\textbf{6.} A ship sails 24 km due north and then 32 km due east. How far is the ship from its starting point?
\end{samepage}

\begin{samepage}
\textbf{7.} The sides of a triangle measure 9 m, 40 m, and 41 m. Verify whether this is a right triangle, and if so, calculate its area.
\end{samepage}

\begin{samepage}
\textbf{8.} A cable is stretched from the top of a 45-meter tower to a point on the ground 28 meters from the base of the tower. Find the length of the cable, and determine how much cable would be saved if the anchor point were moved to 21 meters from the base.
\end{samepage}

\begin{samepage}
