\section*{Solutions to Exercises}
\nopagebreak[4]

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 1: Finding the Hypotenuse}\\[0.5em]
\textbf{Step 1: Identify the given information}\\
The legs of the right triangle are $a = 6$ cm and $b = 8$ cm. We need to find the hypotenuse $c$.

\textbf{Step 2: Apply the Pythagorean Theorem}\\
Using $a^2 + b^2 = c^2$:
\begin{align*}
6^2 + 8^2 &= c^2 \\
36 + 64 &= c^2 \\
100 &= c^2 \\
c &= \sqrt{100} \\
c &= 10 \text{ cm}
\end{align*}
\[\boxed{c = 10 \text{ cm}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 2: Finding a Missing Leg}\\[0.5em]
\textbf{Step 1: Identify the given information}\\
The hypotenuse is $c = 13$ m and one leg is $a = 5$ m. We need to find leg $b$.

\textbf{Step 2: Rearrange and apply the Pythagorean Theorem}\\
Using $b^2 = c^2 - a^2$:
\begin{align*}
b^2 &= 13^2 - 5^2 \\
b^2 &= 169 - 25 \\
b^2 &= 144 \\
b &= \sqrt{144} \\
b &= 12 \text{ m}
\end{align*}
\[\boxed{b = 12 \text{ m}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 3: Diagonal of a Rectangle}\\[0.5em]
\textbf{Step 1: Model the problem}\\
The diagonal of a rectangle forms the hypotenuse of a right triangle with the length and width as legs. Here, $a = 12$ ft and $b = 16$ ft.

\textbf{Step 2: Calculate the diagonal}\\
\begin{align*}
d^2 &= 12^2 + 16^2 \\
d^2 &= 144 + 256 \\
d^2 &= 400 \\
d &= \sqrt{400} \\
d &= 20 \text{ ft}
\end{align*}
\[\boxed{d = 20 \text{ feet}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 4: Verifying a Right Triangle}\\[0.5em]
\textbf{Step 1: Identify the longest side}\\
The sides are 7 cm, 24 cm, and 25 cm. The longest side is 25 cm, which is the candidate for the hypotenuse.

\textbf{Step 2: Test the Pythagorean relationship}\\
\begin{align*}
a^2 + b^2 &= 7^2 + 24^2 = 49 + 576 = 625 \\
c^2 &= 25^2 = 625
\end{align*}

\textbf{Step 3: Compare and conclude}\\
Since $a^2 + b^2 = c^2$ (both equal 625), the triangle is a right triangle.
\[\boxed{\text{Yes, it is a right triangle since } 7^2 + 24^2 = 25^2}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 5: Television Screen Height}\\[0.5em]
\textbf{Step 1: Set up the problem}\\
The diagonal is $c = 55$ inches and the width is $b = 48$ inches. We need to find the height $a$.

\textbf{Step 2: Solve for the height}\\
\begin{align*}
a^2 &= c^2 - b^2 \\
a^2 &= 55^2 - 48^2 \\
a^2 &= 3025 - 2304 \\
a^2 &= 721 \\
a &= \sqrt{721} \\
a &\approx 26.85 \text{ inches}
\end{align*}
\[\boxed{a \approx 26.85 \text{ inches}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 6: Ship's Distance from Starting Point}\\[0.5em]
\textbf{Step 1: Model the problem}\\
The ship's path forms a right triangle with legs of 24 km (north) and 32 km (east). The direct distance is the hypotenuse.

\textbf{Step 2: Calculate the distance}\\
\begin{align*}
d^2 &= 24^2 + 32^2 \\
d^2 &= 576 + 1024 \\
d^2 &= 1600 \\
d &= \sqrt{1600} \\
d &= 40 \text{ km}
\end{align*}
\[\boxed{d = 40 \text{ km}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 7: Verify Right Triangle and Calculate Area}\\[0.5em]
\textbf{Step 1: Test for right triangle}\\
Sides: 9 m, 40 m, 41 m. Longest side: 41 m.
\begin{align*}
9^2 + 40^2 &= 81 + 1600 = 1681 \\
41^2 &= 1681
\end{align*}
Since $9^2 + 40^2 = 41^2$, it is a right triangle.

\textbf{Step 2: Calculate the area}\\
\begin{align*}
\text{Area} &= \frac{1}{2} \times 9 \times 40 \\
&= \frac{1}{2} \times 360 \\
&= 180 \text{ m}^2
\end{align*}
\[\boxed{\text{Right triangle with area } = 180 \text{ m}^2}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 8: Cable Length and Savings}\\[0.5em]
\textbf{Step 1: Calculate original cable length}\\
Tower height: 45 m, distance from base: 28 m.
\begin{align*}
c_1^2 &= 45^2 + 28^2 = 2025 + 784 = 2809 \\
c_1 &= \sqrt{2809} = 53 \text{ m}
\end{align*}

\textbf{Step 2: Calculate new cable length}\\
New distance from base: 21 m.
\begin{align*}
c_2^2 &= 45^2 + 21^2 = 2025 + 441 = 2466 \\
c_2 &= \sqrt{2466} \approx 49.66 \text{ m}
\end{align*}

\textbf{Step 3: Calculate savings}\\
\begin{align*}
\text{Savings} &= 53 - 49.66 \approx 3.34 \text{ m}
\end{align*}
\[\boxed{\text{Original: } 53 \text{ m; New: } 49.66 \text{ m; Savings: } 3.34 \text{ m}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 9: Space Diagonal of a Rectangular Prism}\\[0.5em]
\textbf{Step 1: Find the diagonal of the base}\\
Base dimensions: 3 cm $\times$ 4 cm.
\begin{align*}
d_{\text{base}}^2 &= 3^2 + 4^2 = 9 + 16 = 25 \\
d_{\text{base}} &= 5 \text{ cm}
\end{align*}

\textbf{Step 2: Find the space diagonal}\\
The space diagonal forms a right triangle with the base diagonal (5 cm) and height (12 cm).
\begin{align*}
d_{\text{space}}^2 &= 5^2 + 12^2 = 25 + 144 = 169 \\
d_{\text{space}} &= \sqrt{169} = 13 \text{ cm}
\end{align*}
\[\boxed{d_{\text{space}} = 13 \text{ cm}}\]
\end{solutionbox}
\end{samepage}

\begin{samepage}
\needspace{10\baselineskip}
\begin{solutionbox}
\textbf{Exercise 10: Hiker Distance and Time Saved}\\[0.5em]
\textbf{Step 1: Calculate the direct distance}\\
First hiker: 2.4 km west, then 1.8 km south. The direct path is the hypotenuse.
\begin{align*}
d^2 &= 2.4^2 + 1.8^2 \\
d^2 &= 5.76 + 3.24 \\
d^2 &= 9 \\
d &= 3 \text{ km}
\end{align*}

\textbf{Step 2: Calculate time for each hiker}\\
First hiker's distance: $2.4 + 1.8 = 4.2$ km.
\begin{align*}
\text{Time}_1 &= \frac{4.2}{5} = 0.84 \text{ hours} = 50.4 \text{ minutes} \\
\text{Time}_2 &= \frac{3}{5} = 0.6 \text{ hours} = 36 \text{ minutes}
\end{align*}

\textbf{Step 3: Calculate time saved}\\
\begin{align*}
\text{Time saved} &= 50.4 - 36 = 14.4 \text{ minutes}
\end{align*}
\[\boxed{\text{Direct distance: } 3 \text{ km; Time saved: } 14.4 \text{ minutes}}\]
\end{solutionbox}
\end{samepage}

